/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Provides template rendering, recipient validation, and email delivery.
 * Uses an EmailTransport abstraction so the actual sending mechanism
 * can be swapped (e.g., SendGrid, SES, SMTP) without changing this adapter.
 */

import type {
  NotificationAdapter,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * A rendered email ready for delivery.
 */
export interface RenderedEmail {
  to: string;
  from: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Record of a sent email, stored for observability and testing.
 */
export interface SentEmail {
  to: string;
  from: string;
  subject: string;
  html: string;
  text: string;
  sentAt: Date;
}

/**
 * Abstraction for the actual email sending mechanism.
 * Implement this to integrate with a real email provider.
 */
export interface EmailTransport {
  sendMail(email: RenderedEmail): Promise<{ messageId: string }>;
}

/**
 * Default in-memory transport for development and testing.
 * Stores sent emails in an array for inspection.
 */
export class InMemoryTransport implements EmailTransport {
  private sent: SentEmail[] = [];

  async sendMail(email: RenderedEmail): Promise<{ messageId: string }> {
    this.sent.push({ ...email, sentAt: new Date() });
    const messageId = `msg-${Date.now()}-${this.sent.length}`;
    return { messageId };
  }

  getSentEmails(): SentEmail[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

/**
 * Email configuration options.
 */
export interface EmailAdapterConfig {
  fromAddress: string;
  fromName: string;
  transport?: EmailTransport;
}

const DEFAULT_CONFIG: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  fromName: 'TaskFlow Pro',
};

/**
 * Template definitions keyed by notification type.
 * Each template has a subject function and body function that receive the payload.
 */
interface EmailTemplate {
  subject: (payload: NotificationPayload) => string;
  html: (payload: NotificationPayload) => string;
  text: (payload: NotificationPayload) => string;
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

const EMAIL_TEMPLATES: Record<NotificationType, EmailTemplate> = {
  order_confirmation: {
    subject: (p) => p.subject,
    html: (p) => {
      const orderId = (p.metadata?.orderId as string) ?? '';
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        `<h1>Order Confirmation</h1>`,
        `<p>Thank you for your order <strong>${escapeHtml(orderId)}</strong>.</p>`,
        `<p>${escapeHtml(p.body)}</p>`,
        '<p>We will notify you when your order ships.</p>',
        '</div>',
      ].join('\n');
    },
    text: (p) => {
      const orderId = (p.metadata?.orderId as string) ?? '';
      return `Order Confirmation\n\nThank you for your order ${orderId}.\n${p.body}\nWe will notify you when your order ships.`;
    },
  },

  order_status_update: {
    subject: (p) => p.subject,
    html: (p) => {
      const orderId = (p.metadata?.orderId as string) ?? '';
      const newStatus = (p.metadata?.newStatus as string) ?? '';
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        `<h1>Order Update</h1>`,
        `<p>Your order <strong>${escapeHtml(orderId)}</strong> is now <strong>${escapeHtml(newStatus)}</strong>.</p>`,
        `<p>${escapeHtml(p.body)}</p>`,
        '</div>',
      ].join('\n');
    },
    text: (p) => {
      const orderId = (p.metadata?.orderId as string) ?? '';
      const newStatus = (p.metadata?.newStatus as string) ?? '';
      return `Order Update\n\nYour order ${orderId} is now ${newStatus}.\n${p.body}`;
    },
  },

  welcome: {
    subject: (p) => p.subject,
    html: (p) => {
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        `<h1>Welcome to TaskFlow Pro!</h1>`,
        `<p>${escapeHtml(p.body)}</p>`,
        '<p>Get started by creating your first order.</p>',
        '</div>',
      ].join('\n');
    },
    text: (p) => {
      return `Welcome to TaskFlow Pro!\n\n${p.body}\nGet started by creating your first order.`;
    },
  },

  account_updated: {
    subject: (p) => p.subject,
    html: (p) => {
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        `<h1>Account Updated</h1>`,
        `<p>${escapeHtml(p.body)}</p>`,
        '</div>',
      ].join('\n');
    },
    text: (p) => {
      return `Account Updated\n\n${p.body}`;
    },
  },
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;
  private transport: EmailTransport;

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.transport = this.config.transport ?? new InMemoryTransport();
  }

  /**
   * Validate that the recipient looks like a valid email address.
   */
  private validateRecipient(recipient: string): boolean {
    // Basic email validation: must have local@domain format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(recipient);
  }

  /**
   * Resolve the display "from" header.
   */
  private resolveFrom(): string {
    return `${this.config.fromName} <${this.config.fromAddress}>`;
  }

  /**
   * Render a notification payload into a full email using the appropriate template.
   */
  renderEmail(payload: NotificationPayload): RenderedEmail {
    const template = EMAIL_TEMPLATES[payload.type];

    return {
      to: payload.recipient,
      from: this.resolveFrom(),
      subject: template.subject(payload),
      html: template.html(payload),
      text: template.text(payload),
    };
  }

  /**
   * Send a notification via email.
   * Validates the recipient, renders the template, and delivers via transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!this.validateRecipient(payload.recipient)) {
      this.logger.warn(`Invalid email recipient: ${payload.recipient}`);
      return {
        success: false,
        notificationId: '',
        channel: this.channel,
        error: `Invalid email address: ${payload.recipient}`,
      };
    }

    const email = this.renderEmail(payload);
    this.logger.info(`Sending email to ${email.to}: ${email.subject}`);

    try {
      const result = await this.transport.sendMail(email);
      this.logger.info(`Email sent successfully: ${result.messageId}`);

      return {
        success: true,
        notificationId: '', // filled in by NotificationService
        channel: this.channel,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send email to ${email.to}: ${errorMessage}`);

      return {
        success: false,
        notificationId: '',
        channel: this.channel,
        error: `Email delivery failed: ${errorMessage}`,
      };
    }
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryTransport).
   */
  getTransport(): EmailTransport {
    return this.transport;
  }
}

