import { describe, it, expect, beforeEach, vi } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
} from '../../src/adapters/email.adapter.js';
import type {
  EmailTransport,
  RenderedEmail,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'email',
    type: 'order_confirmation',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
    adapter = new EmailAdapter({ transport });
  });

  describe('channel', () => {
    it('should report email channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('renderEmail', () => {
    it('should render order_confirmation template with HTML and text', () => {
      const payload = makePayload();
      const rendered = adapter.renderEmail(payload);

      expect(rendered.to).toBe('alice@example.com');
      expect(rendered.from).toContain('TaskFlow Pro');
      expect(rendered.from).toContain('noreply@taskflowpro.com');
      expect(rendered.subject).toBe('Order Confirmation: order-1');
      expect(rendered.html).toContain('<h1>Order Confirmation</h1>');
      expect(rendered.html).toContain('order-1');
      expect(rendered.text).toContain('Order Confirmation');
      expect(rendered.text).toContain('order-1');
    });

    it('should render order_status_update template', () => {
      const payload = makePayload({
        type: 'order_status_update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to shipped.',
        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'shipped' },
      });

      const rendered = adapter.renderEmail(payload);
      expect(rendered.html).toContain('<h1>Order Update</h1>');
      expect(rendered.html).toContain('shipped');
      expect(rendered.text).toContain('shipped');
    });

    it('should render welcome template', () => {
      const payload = makePayload({
        type: 'welcome',
        subject: 'Welcome to TaskFlow Pro',
        body: 'Hi Alice, welcome to TaskFlow Pro!',
        metadata: { userId: 'user-1' },
      });

      const rendered = adapter.renderEmail(payload);
      expect(rendered.html).toContain('Welcome to TaskFlow Pro');
      expect(rendered.html).toContain('Get started');
      expect(rendered.text).toContain('Get started');
    });

    it('should render account_updated template', () => {
      const payload = makePayload({
        type: 'account_updated',
        subject: 'Account Updated',
        body: 'Your account settings have been updated.',
        metadata: {},
      });

      const rendered = adapter.renderEmail(payload);
      expect(rendered.html).toContain('<h1>Account Updated</h1>');
      expect(rendered.text).toContain('Account Updated');
    });

    it('should escape HTML in body content', () => {
      const payload = makePayload({
        body: '<script>alert("xss")</script>',
      });

      const rendered = adapter.renderEmail(payload);
      expect(rendered.html).not.toContain('<script>');
      expect(rendered.html).toContain('&lt;script&gt;');
    });
  });

  describe('recipient validation', () => {
    it('should reject invalid email addresses', async () => {
      const payload = makePayload({ recipient: 'not-an-email' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should reject emails without domain', async () => {
      const payload = makePayload({ recipient: 'user@' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should reject empty recipient', async () => {
      const payload = makePayload({ recipient: '' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
    });

    it('should accept valid email addresses', async () => {
      const payload = makePayload({ recipient: 'user@domain.com' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
    });
  });

  describe('send', () => {
    it('should send email via transport and return success', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');

      const sent = transport.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
      expect(sent[0]?.html).toContain('<h1>');
      expect(sent[0]?.text).toContain('Order Confirmation');
    });

    it('should handle transport errors gracefully', async () => {
      const failingTransport: EmailTransport = {
        sendMail: async () => {
          throw new Error('SMTP connection refused');
        },
      };
      const failAdapter = new EmailAdapter({ transport: failingTransport });

      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('SMTP connection refused');
    });

    it('should handle non-Error throw from transport', async () => {
      const failingTransport: EmailTransport = {
        sendMail: async () => {
          throw 'string error';
        },
      };
      const failAdapter = new EmailAdapter({ transport: failingTransport });

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('string error');
    });

    it('should send multiple emails independently', async () => {
      await adapter.send(makePayload({ recipient: 'alice@example.com' }));
      await adapter.send(makePayload({ recipient: 'bob@example.com' }));

      const sent = transport.getSentEmails();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[1]?.to).toBe('bob@example.com');
    });
  });

  describe('configuration', () => {
    it('should use default from address', () => {
      const defaultAdapter = new EmailAdapter({ transport });
      const rendered = defaultAdapter.renderEmail(makePayload());

      expect(rendered.from).toBe('TaskFlow Pro <noreply@taskflowpro.com>');
    });

    it('should allow custom from address', () => {
      const customAdapter = new EmailAdapter({
        fromAddress: 'support@custom.com',
        fromName: 'Custom App',
        transport,
      });

      const rendered = customAdapter.renderEmail(makePayload());
      expect(rendered.from).toBe('Custom App <support@custom.com>');
    });
  });
});

describe('InMemoryTransport', () => {
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
  });

  it('should store sent emails', async () => {
    const email: RenderedEmail = {
      to: 'test@example.com',
      from: 'noreply@test.com',
      subject: 'Test',
      html: '<p>Hello</p>',
      text: 'Hello',
    };

    const result = await transport.sendMail(email);
    expect(result.messageId).toBeTruthy();

    const sent = transport.getSentEmails();
    expect(sent).toHaveLength(1);
    expect(sent[0]?.to).toBe('test@example.com');
    expect(sent[0]?.sentAt).toBeInstanceOf(Date);
  });

  it('should clear sent emails', async () => {
    await transport.sendMail({
      to: 'test@example.com',
      from: 'noreply@test.com',
      subject: 'Test',
      html: '<p>Hello</p>',
      text: 'Hello',
    });

    transport.clear();
    expect(transport.getSentEmails()).toHaveLength(0);
  });

  it('should return unique message IDs', async () => {
    const email: RenderedEmail = {
      to: 'test@example.com',
      from: 'noreply@test.com',
      subject: 'Test',
      html: '<p>Hello</p>',
      text: 'Hello',
    };

    const r1 = await transport.sendMail(email);
    const r2 = await transport.sendMail(email);
    expect(r1.messageId).not.toBe(r2.messageId);
  });
});
